#!/usr/bin/env python3
"""
rxmedcalc.com — FAQ Injector v2
Injects static HTML FAQ sections before </body> for pages with no FAQ.
Run from repo root: python3 inject_faqs_v2.py
"""
import re, shutil
from pathlib import Path

# FAQ CSS to inject if .fi/.fq not present
FAQ_CSS = """
    .faq-sec{margin:28px 0}.faq-sec h2{font-size:1.05rem;font-weight:700;color:var(--primary-dark,#0c4a6e);margin-bottom:14px;padding-bottom:8px;border-bottom:2px solid var(--border,#dce4ef)}
    .fi{border-bottom:1px solid var(--border,#e5e7eb);padding:14px 0}.fi:last-child{border-bottom:none}
    .fq{font-size:0.9rem;font-weight:600;color:var(--text,#0d1b2a);cursor:pointer;display:flex;justify-content:space-between;align-items:flex-start;gap:10px;user-select:none}
    .fq::after{content:'＋';color:var(--primary,#0369a1);font-size:1rem;flex-shrink:0;transition:transform 0.2s}
    .fi.op .fq::after{transform:rotate(45deg)}
    .fa{max-height:0;overflow:hidden;transition:max-height 0.35s ease;font-size:0.85rem;color:var(--text-muted,#4b5563);line-height:1.75}
    .fi.op .fa{max-height:600px;padding-top:8px}"""

FAQ_JS = """
  function tf(el){var fi=el.closest('.fi');var was=fi.classList.contains('op');document.querySelectorAll('.fi').forEach(function(e){e.classList.remove('op')});if(!was)fi.classList.add('op')}"""

def build_faq_html(faqs):
    items = []
    for q, a in faqs:
        items.append(
            f'      <div class="fi"><div class="fq" onclick="tf(this)">{q}'
            f'</div><div class="fa">{a}</div></div>'
        )
    return (
        '\n  <div class="faq-sec">\n'
        '    <h2>Frequently Asked Questions</h2>\n'
        + '\n'.join(items) +
        '\n  </div>'
    )

